using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns JsonTypeInfo<Person> directly, no cast needed
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded → {info!.Type.Name}");
}

// Now demonstrate a case where metadata is NOT available.
// Use a custom resolver that only knows about Person.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new PersonOnlyResolver()
};

if (limited.TryGetTypeInfo<int>(out JsonTypeInfo<int>? intInfo))
{
    Console.WriteLine($"TryGetTypeInfo<int> succeeded → {intInfo!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<int> returned false — metadata not available");
}

// --- Types ---------------------------------------------------------------

public record Person(string Name, int Age);

/// A resolver that only resolves Person; returns null for everything else.
file sealed class PersonOnlyResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
    {
        if (type == typeof(Person))
        {
            return JsonMetadataServices.CreateObjectInfo<Person>(options,
                new JsonObjectInfoValues<Person>
                {
                    ObjectCreator = null,
                    SerializeHandler = (writer, value) =>
                    {
                        writer.WriteStartObject();
                        writer.WriteString("name", value.Name);
                        writer.WriteNumber("age", value.Age);
                        writer.WriteEndObject();
                    }
                });
        }
        return null;
    }
}
